var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"도착했습니다, 누님!","JPN":"着きました、姉貴！","ENG":"We've arrived, ma'am!","TWN":"到了，大姊頭！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"여기부터는 침식파의 영향권이라 저희는 못 들어갈 것 같습니다.","JPN":"ここからは侵食波の影響圏内になるので、俺たちは入れそうにないです。","ENG":"The Corruption rays are too strong that I don't think we can go any further from here.","TWN":"從這裡開始就是侵蝕波的影響範圍了，我們的話就進不去了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그렇군요. 수고했어요.","JPN":"そうですか。ご苦労様でした。","ENG":"Okay. Good work.","TWN":"原來如此，辛苦了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사례금입니다. 기름값이라고 생각하고 받으세요.","JPN":"これは謝礼金です。ガソリン代だと思って受け取ってください。","ENG":"Here's your pay. Think of it as gas money.","TWN":"這是酬金。就當是油錢，收下吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"가, 감사합니다! 살펴가십시오!","JPN":"あ、ありがとうございます！　どうかお気をつけて！","ENG":"Th-thank you! Good luck!","TWN":"非，非常感謝！請慢走！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"어제의 적이 오늘의 협력자라…….","JPN":"昨日の敵が今日の協力者、か……","ENG":"Yesterday's enemy is today's ally, huh...?","TWN":"昨日的敵人成為了今天的合作夥伴……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"크, 이런 게 바로 용병의 프로페셔널 아니겠어?","JPN":"くぅ～これぞ傭兵のプロフェッショナルだな！","ENG":"Damn, guess that's what it means to be a pro mercenary, eh?","TWN":"哼，這才是雇傭兵的專業精神，不是嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"그런데 저 여자는 대체 저렇게 위험한 곳에 왜 가려고 하는 걸까요?","JPN":"でもあの女、なんであんな危険な場所に行くんですかね？","ENG":"But why does she even want to go to such a dangerous place?","TWN":"但那個女人為什麼要去那樣危險的地方呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"쯧쯧, 이래서 네가 아직 애송이라는 거야.","JPN":"チッチッ。これだからお前はまだガキなんだよ。","ENG":"Tsk, tsk. That's why you're still a punk.","TWN":"嘖嘖，所以說你還是個不入流。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그야 복수심을 품은 외로운 거미가 스캐빈저에게 독니를 꽂으러 가는 거지.","JPN":"決まってるだろ。復讐心に燃える孤独なクモが、スカベンジャーに再び毒牙をぶっ刺しに行くんだ。","ENG":"It's because the vengeful lonely spider is going to sink her venomous fangs into the Scavengers.","TWN":"懷著復仇之心的獨狼蜘蛛，正準備將她的毒牙刺入清道夫體內。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"네에?","JPN":"ええっ……？","ENG":"What?","TWN":"啊啊？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"어쩌면 우리는…….","JPN":"もしかしたら俺たちは……","ENG":"Maybe...","TWN":"哼哼，也許我們……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"이곳에서 곧 엄청난 복수극을 마주하게 될지도 몰라.","JPN":"この後、とんでもない復讐劇を目撃することになるかもしれないな。","ENG":"We might soon face a tremendous revenge here.","TWN":"可能很快就會在這裡迎來一場盛大的復仇戲碼。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……코러스.","JPN":"……コーラス。","ENG":"...Chorus.","TWN":"……Chorus。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제프티 사가 파산 절차를 밟은 뒤, 연구 자료를 빼돌리면서 관련 문서를 본 적이 있어.","JPN":"ジェフティ社が破産手続きを終えた後、研究資料を盗んで関係書類に目を通したことがある。","ENG":"After Jehuty went through the bankruptcy proceedings, I saw related documents while stealing their research material.","TWN":"在傑夫堤進行破產程式時，我曾經偷看過他們的研究資料和相關檔。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제프티를 뒤에서 조종하던 그림자들이 막대한 자본을 들여 인양해 낸 로스트 쉽…….","JPN":"ジェフティを裏で操っていたシャドウたちが莫大な資本を投入して引き揚げたロストシップ……","ENG":"The Shadows that controlled Jehuty behind the scenes spent immense capital to salvage the Lost Ship...","TWN":"在幕後操縱傑夫堤的暗影們花費鉅資打撈上來的失落艦船……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"원래 이건 엘리시움의 세계에서 사용되던 함선이야.","JPN":"もともとこれはエリシウムの世界で使われた艦船。","ENG":"This was originally a ship used in Elysium's world.","TWN":"這原本是愛樂世界中使用的艦船。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당연하게도 이면세계에 오랫동안 방치된 함선을 그대로 쓸 수는 없었어.","JPN":"しかし当然ながら、長い間裏世界に放置されていた艦船をそのまま使えるはずはなかった。","ENG":"But of course, it can't be used as is because it has been abandoned in the Counterside for all this time.","TWN":"理所當然地，長期被遺棄在異界的艦船無法直接使用。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가장 핵심이 되는 메인 프레임을 제외하면, 개장 및 보수 작업에서 제프티의 기술력이 대거 사용되었지.","JPN":"要となるメインフレーム以外は改装や補修作業が行われ、ジェフティの技術力が多く使われた。","ENG":"Excluding the essential main frame, Jehuty's technology was used extensively to remodel and repair it.","TWN":"除了最核心的主框架外，改造和維修工程中使用了大量傑夫堤的技術。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그로 인해 발생하는 필연적인 문제들…….","JPN":"それによって発生する必然的な問題……","ENG":"And the inevitable problems that arise as a result are...","TWN":"由此產生的必然問題……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"부품의 호환성, 표준화되지 않은 OS, 양산화 설비를 갖추기 위한 재해석 등등…….","JPN":"部品の互換性、標準化されていないOS、量産化設備を備えるための再解析……","ENG":"compatibility of parts, non-standardized OS, a reinterpretation of the ship for mass production, and so on...","TWN":"部件的相容性、未標準化的作業系統、為量產設備進行的重新解釋等等……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이런저런 사정으로, 제프티 사의 손을 거친 코러스는 꽤나 결이 다른 함선이 되었어.","JPN":"結果的に、ジェフティ社の手に渡ったコーラスは、最初とはかなり違う艦船になった。","ENG":"For one reason or another, Chorus has become an entirely different ship after Jehuty got its hands on it.","TWN":"由於種種原因，經由傑夫堤公司之手，Chorus變成了一艘截然不同的艦船。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오히려 상당부분은 관리국 표준 함선과 비슷한 구조를 띠게 되었지.","JPN":"どちらかと言えば、管理局の標準艦船に近い構造だった。","ENG":"The majority of it now resembles a similar structure to that of the Administration ships.","TWN":"反而在很大程度上呈現出與管理局標準艦船相似的結構。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그림자들이 운용하려고 건조한 함선이었겠지만, 결국 엔지니어는 이 세계의 사람들이니까.","JPN":"シャドウたちが運用するために建造した艦船だろうけど、所詮エンジニアはこの世界の人間だから。","ENG":"Though the ship was built to be operated by Shadows, the engineers who fixed it were from this world after all.","TWN":"雖然是暗影們建造的艦船，但最終的工程師還是這個世界的人。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래, 이를테면…….","JPN":"そう、例えば……","ENG":"Yes, for instance...","TWN":"嗯，舉例來說……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"함선의 동력부와 주무장인 고출력 함포가 직렬로 연결되어 있는 이 설계…….","JPN":"艦船動力部とメイン武装である高出力の艦砲が直列接続されているこの設計……","ENG":"the design of the ship's engine and its main weapon, the high-powered cannon, being connected in series...","TWN":"把艦船的動力部和主武裝大功率艦炮串聯的這個設計……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이런 방식은 전형적인 관리국 표준 함선의 설계 방식이야.","JPN":"これは典型的な管理局標準艦船と同じ方式。","ENG":"This is the typical Administration's standard ship designs.","TWN":"這種是典型的管理局標準艦船的設計方式。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"관리국 함선은 높은 출력과 강력한 화력으로 대침식전을 보조해야 하니까.","JPN":"管理局の艦船は高出力・高火力で耐侵食戦をサポートしなけらばならないから。","ENG":"The Administration ships had to support anti-C.O. warfare with high-output and powerful firepower.","TWN":"管理局的艦船需要以高輸出和強大火力來支援抗侵蝕戰。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"원래 코러스였다면, 절대 이런 구조가 아니었겠지.","JPN":"本来のコーラスは、決してこんな構造ではなかったはず。","ENG":"The original Chorus would have never been designed this way.","TWN":"如果是原來的Chorus，絕對不會是這種結構。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그들에게는 단원들의 연주를 확산시키기 위한 <color=#ffd34c>특수 목적</color> 설비가 더 중요했을 거야.","JPN":"彼らは団員の演奏を拡散するための<color=#ffd34c>特殊目的</color>設備を優先したに違いない。","ENG":"To them, their <color=#ffd34c>special objective</color> of amplifying their members' performance was of more importance.","TWN":"對他們來說，能滿足他們擴散團員演奏的<color=#ffd34c>特殊目的</color>的設備會更重要。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여기서 발생하는 두 세계 간의 기술 격차…….","JPN":"ここで発生する、二つの世界の技術的格差……","ENG":"This is where the two worlds' technological gap starts to show...","TWN":"從這裡便生出了兩個世界之間技術理念的不同……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"따라서 원래 코러스와의 설계 간극을 메워주기 위한 별도의 장치가 필요로 했겠지.","JPN":"従って、元のコーラスの機能を再現するために、別途装置が必要になったのだろう。","ENG":"Accordingly, they needed a separate device to bridge the gap between the original Chorus' design and theirs.","TWN":"因此，需要一個單獨的裝置來填補與原本設計初衷的差距。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"엘리시움 그림자들의 연주로 발생되는 침식파를 공명, 확산시키는 장치…….","JPN":"エリシウムシャドウたちの演奏から発生する侵食波を共鳴、拡散させる装置……","ENG":"Elysium Shadows had a device that resonated and expanded the reach of the Corruption rays generated by their performing...","TWN":"一個能夠共鳴並擴散愛樂暗影演奏時所產生的侵蝕波的裝置……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"함포의 에너지를 다른 형태의 에너지로 변환시켜주는 <color=#ffd34c>컨버터</color>가 설치되어 있을 거야.","JPN":"艦砲のエネルギーを別の形のエネルギーに変換する<color=#ffd34c>コンバーター</color>が設置されているはず。","ENG":"So, I'm certain that there must be a <color=#ffd34c>converter</color> that turns the cannon's energy into a different form of energy.","TWN":"我推斷這裡一定安裝了某種將艦炮能量轉換為其他形式能量的<color=#ffd34c>轉換器</color>。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 컨버터를 모방할 수 있다면…….","JPN":"そして、そのコンバーターを模倣することができれば……","ENG":"If I can just emulate that converter...","TWN":"如果能模仿那個轉換器的話……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"고출력 좌표 신호기, <color=#ffd34c>등대</color>라…….","JPN":"高出力座標信号機、<color=#ffd34c>灯台</color>……","ENG":"The high-powered coordinate signaler, <color=#ffd34c>Lighthouse</color>...","TWN":"高能座標信號器，<color=#ffd34c>燈塔</color>啊……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"구원기사단에게 이 장치의 존재와 위치에 대한 정보를 흘리면 된다는 말씀일까요?","JPN":"救世騎士団にこの装置の存在と場所に関する情報を流せばいいという意味ですか？","ENG":"Are you saying all I have to do is leak the information about this device's existence and location to the Knights of Redemption?","TWN":"你的意思是，只需向救贖騎士團透露這個裝置的存在和位置的資訊嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네. 구체적인 정보는 노출하지 않아도 괜찮아요.","JPN":"はい。具体的な情報までは明かさなくて構いません。","ENG":"Yes. You don't need to reveal anything specific, however.","TWN":"是的。具體細節不需要透露。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어디까지나 그들 스스로 활용방법을 떠올리도록 해주세요.","JPN":"あくまで彼らが自ら活用方法に気づくようにしてください。","ENG":"Let them come up with ways to use it themselves.","TWN":"請務必讓他們自己想出如何利用它的方法。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 저에겐 이 장치가 무엇인지 정도는 알려주셔야 하지 않을까요, 대장님?","JPN":"なら、せめて私にはこの装置が何なのかぐらいは教えてくれてもいいのではないですか、隊長？","ENG":"Then, shouldn't you at least tell me what this device is, Commander?","TWN":"那麼，至少應該告訴我這個裝置是什麼吧，隊長？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하. 물론이에요, 스완.","JPN":"はは。もちろんです、スワンさん。","ENG":"Haha. Of course, Swan.","TWN":"哈哈，當然了，史旺。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"등대라는 건, 구 관리국에서 허수공간을 돌파하기 위해 만든 좌표 신호기입니다.","JPN":"灯台というのは、虚数空間を突破するために旧管理局が作った座標信号機です。","ENG":"The Lighthouse is a coordinate signaler made by the Administration to break through the imaginary space.","TWN":"所謂燈塔，是舊管理局為了突破虛數空間而製造的座標信號器。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"허수공간을 돌파한다고요……?","JPN":"虚数空間を突破する……？","ENG":"Break through the imaginary space...?","TWN":"突破虛數空間……？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"입력된 파장을 고출력으로 <color=#ffd34c>확산</color>시켜 시시각각 좌표가 왜곡되는 허수공간에서도 고정된 좌표 값을 제공해 주거든요.","JPN":"入力された波長を高出力で<color=#ffd34c>拡散</color>させ、時々刻々と座標の歪曲が発生する虚数空間でも固定座標値を提供してくれるんです。","ENG":"By <color=#ffd34c>expanding</color> the input wavelength with high-output, it provides fixed coordinates to the imaginary space where the coordinates get distorted by the hour.","TWN":"將輸入的波長以極高輸出進行<color=#ffd34c>擴散</color>，那麼即使在時刻扭曲座標的虛數空間中也能夠提供固定的座標值。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 나쁘지 않은 발상이었지만, 결국 결함이 있어서 실전 배치되지는 않았어요.","JPN":"まあ、発想自体は悪くなかったんですが。欠陥があったので最終的に実戦配置されることはありませんでした。","ENG":"It's not a bad idea, but it was never implemented due to a flaw.","TWN":"嗯，雖然這個想法不錯，但最終因為有缺陷而沒有投入實戰。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"말씀 안 하셔도 알 것 같군요.","JPN":"なんとなく想像がつきますね。","ENG":"I think I know what you're talking about.","TWN":"即使你不說，我也明白了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"허수공간에서 좌표를 고정시킨다는 행위 자체가 침식체들에게도 자기 위치를 알려주는 꼴…….","JPN":"虚数空間で座標を固定するということは、侵食体にもこちらの位置を教えてあげるのと同然……","ENG":"Fixing the coordinates in the imaginary space is the same as exposing your location to the C.O.s....","TWN":"在虛數空間留下固定座標的行為本身就等於告訴侵蝕體自己的位置……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"누가 만들었는지 모르겠지만, 이래서는 등대라는 이름이 무색할 지경이네요.","JPN":"誰が作ったかは分かりませんが、灯台という名が泣きますね。","ENG":"I don't know who made it, but it seems to make the name Lighthouse meaningless.","TWN":"也不知道是誰建造的，這樣的話，燈塔這個名字就顯得名不副實了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"역시 스완 씨는 똑똑하시네요.","JPN":"さすがスワンさん。理解が早いですね。","ENG":"Bright as ever, Swan.","TWN":"你果然很聰明啊，史旺。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 그게 또 그렇지만도 않답니다. 등대는 결국 등대거든요.","JPN":"でも、必ずしもそうでもありません。灯台は結局灯台なんです。","ENG":"But not all is as it seems. The Lighthouse is still a lighthouse, after all.","TWN":"但那也不完全這樣。燈塔終究還是燈塔。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"발상을 역전시키라는 말도 있잖아요? 인간이 길을 찾는 데는 부적합 할 지라도…….","JPN":"発想を逆転させる……という言葉があるでしょう。人間の道探しにおいては少々不適合なところもありますが……","ENG":"Ever heard of the phrase of \\"perspective shift?\\" It may be unsuited for humans to find a way...","TWN":"不是有個詞叫”轉換視角“嗎？也許對人類不太適合……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"활용하기에 따라 눈먼 <color=#ffd34c>패배자들</color>에게도 길을 가르쳐 줄 수 있으니까.","JPN":"活用次第では、盲目な<color=#ffd34c>敗北者たち</color>にも道を教えてあげることができる。","ENG":"But it can show a path to even the blind <color=#ffd34c>losers</color> depending on how one uses it.","TWN":"但只要好好利用，甚至可以給那些迷失了的<color=#ffd34c>失敗者</color>指引方向。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아. 다행히 컨버터는 파손되지는 않았군.","JPN":"……ふう。幸い、コンバーターは破損していなかった。","ENG":"Good. The converter is not damaged.","TWN":"很好。幸好轉換器沒有損壞。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리포트 인자</color>와 별도의 <color=#ffd34c>동력원</color>이 추가로 필요로 하겠지만.","JPN":"<color=#ffd34c>クリフォトファクター</color>と別の<color=#ffd34c>動力源</color>が必要になるけど……","ENG":"However, I'll need a <color=#ffd34c>Qliphoth Factor</color> and a separate <color=#ffd34c>power source</color>.","TWN":"現在還需要<color=#ffd34c>逆卡巴拉因子</color>和額外的<color=#ffd34c>動力源</color>。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"같은 원리의 이 장치라면, 등대처럼 클리포트 인자 파동을 확산시킬 수 있을지도 모르지.","JPN":"同じ原理で動くこの装置なら、灯台のようにクリフォトファクターの波動を拡散させることができるかもしれない。","ENG":"If the device has the same principle, I might be able to spread the Qliphoth Factor wavelengths like the Lighthouse.","TWN":"如果這個裝置也是同樣的原理，或許可以像燈塔一樣擴散逆卡巴拉因子波動。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그게 가능하다면…….","JPN":"もし本当にそれが叶ったら……","ENG":"And if that's possible...","TWN":"如果可行的話……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"파노라마로 장치의 기능을 모방하기 위해서는 컨버터의 작동을 육안으로 확인해야 해.","JPN":"パノラマで装置の機能を模倣するためには、コンバーターの作動を肉眼で一度確認しなければ。","ENG":"I'll need to see the converter working with my own eyes to imitate the device's features with Panorama.","TWN":"嗯，我需要親眼確認轉換器的運作，才能模仿裝置的功能。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상대로, OS는 관리국 표준 오퍼레이팅 시스템…….","JPN":"予想どおり、OSは管理局の標準オペレーティングシステム……","ENG":"Just as I expected. The OS is the Administration's standard operating system...","TWN":"果然，是管理局的標準作業系統……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"잔량이 얼마 남지 않았지만, 동력부 자체는 살아있군. 이거라면…….","JPN":"残量はわずかだけど、動力部はまだ生きている。これなら……","ENG":"The engine doesn't have much power, but it's still alive. Maybe–","TWN":"雖然剩餘量不多，但動力部本身完好。如此一來……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 전에……. 예정된 불청객들이 먼저 도착한 모양이군…….","JPN":"その前に……招かれざる客が、予定通りに着いたみたいね。","ENG":"Before that... it seems that some unexpected guests have arrived.","TWN":"看來在那之前……預定的不速之客已經先到了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"핫핫핫! 누가 우리 물건에 함부로 손을 대나 했는데.","JPN":"はははは！　うちの物に誰が手を出したのかと思ったら……","ENG":"Gah hah hah! I was wondering who would dare to mess with our stuff.","TWN":"哈哈哈！我還在想是誰敢隨便動我們的東西。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L17_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"이런 고철 더미 속에서 한 송이의 푸른 장미를 만나게 될 줄이야.","JPN":"こんなガラクタの山の中で、一輪の青いバラに出会うとは。","ENG":"But I never thought I'd find a blue rose in a pile of scrap metal.","TWN":"沒想到在這堆廢鐵中會遇到一朵藍玫瑰。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"사인을 부탁해도 될까, 세뇨리타?","JPN":"サインをお願いできるかな、セニョリータ？","ENG":"May I ask for your autograph, senorita?","TWN":"可以請你簽個名嗎，小姐？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"사인을 받고 싶은 것치곤, 환영 인사가 조금 거칠군요.","JPN":"サインがほしいわりには荒々しい歓迎挨拶ですね。","ENG":"Aside from wanting my autograph, your greeting seems a bit rough, don't you think?","TWN":"想要簽名的話，這歡迎儀式有點粗暴呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"스캐빈저 규칙 하나. 우리 물건에 손을 댄 녀석은 누구든 손모가지를 날린다.","JPN":"スカベンジャーのルール、その一。俺たちの物に手を出すやつらはすべてぶっ潰す。","ENG":"The Scavengers' Rule Number One: Whoever tries to steal from us gets their wrist chopped off.","TWN":"清道夫規則之一，誰碰我們的東西，就把誰的手砍下來。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"설령, 그게 샤레이드의 유명 인사라고 할지라도 말이야.","JPN":"例え相手がシャレードの有名人だとしてもな。","ENG":"Even if that person is a famous celebrity from Charade.","TWN":"即使是查雷德的名人也一樣。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그러니 사인 대신 그 손목을 받아가도록 하지.","JPN":"だからサインの代わりに、その手首をもらうとしよう。","ENG":"So, instead of your autograph, I'll take that hand of yours.","TWN":"所以，作為替代，就讓我拿走你的手腕吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"에헷? 이거 진짜야? 진짜 스완이잖아!?","JPN":"ええっ？　マジか？　ガチのスワンじゃん！","ENG":"Whoa. Is this for real? Is that really Swan?!","TWN":"喔喔？這是真的嗎？真的是史旺耶！？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"어머나! 저 길고 가느다란 손가락 좀 봐! 빨리 썰고 싶어!","JPN":"やべえ！　あの細長い指！　早く切り刻みてえ！","ENG":"Oh, man! Look at those long and thin fingers! I can't wait to chop 'em off!","TWN":"天哪！你看那又長又細的手指！真想快點給它切下來！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"그거 잘됐군요. 제게도 한 가지 규칙이 있답니다.","JPN":"それはよかったですね。私にも一つ、ルールがありまして。","ENG":"Good timing. I also have a rule of my own.","TWN":"那真是太好了。我也有一條規矩。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"무대 뒤편에서 제 얼굴을 본 사람은 결코 살려두지 않는다는 규칙이죠.","JPN":"舞台裏で私の顔を見た者は決して生かして帰さないというルールです。","ENG":"My rule is that anyone who sees my face behind the stage will not be spared.","TWN":"在舞台背後見過我臉的人，絕對不能活著離開。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"훗, 그거 재밌군.","JPN":"ふっ、それは面白い。","ENG":"Heh, that's funny.","TWN":"哈，那還真有意思。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"그러니 곧 있을 주연 배우의 등장을 위하여 춤추고 노래하도록 하세요.","JPN":"この後始まる主役の登場シーンのために、歌って踊りなさい。","ENG":"So please make sure to sing and dance as the lead role will soon appear.","TWN":"所以，為了即將登場的主角，請盡情歌舞吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"그게 이 무대에서 코러스를 맡은 당신들의 역할이니까.","JPN":"それがこの舞台でコーラスを担当しているあなたたちの役割ですから。","ENG":"That will be your roles on the stage called Chorus.","TWN":"這便是你們在這個舞台上擔任的合唱的角色。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};